import { redirect } from "next/navigation"
import { createClient } from "@/lib/supabase/server"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import Link from "next/link"
import { ArrowLeft, User } from "lucide-react"

export default async function AdminMastersPage() {
  const supabase = await createClient()

  const {
    data: { user },
  } = await supabase.auth.getUser()
  if (!user) {
    redirect("/auth/login")
  }

  // Проверяем, что пользователь админ (опционально)
  const { data: adminUser } = await supabase
    .from("admin_users")
    .select("*")
    .eq("id", user.id)
    .single()

  if (!adminUser) {
    redirect("/")
  }

  // Загружаем мастеров
  const { data: masters } = await supabase
    .from("masters")
    .select("*")
    .order("name")

  return (
    <div className="min-h-screen bg-gray-50">
      <header className="bg-white border-b">
        <div className="container mx-auto px-4">
          <div className="flex items-center justify-between h-16">
            <Link href="/admin" className="inline-flex items-center gap-2 text-gray-600 hover:text-rose-600">
              <ArrowLeft className="w-4 h-4" />
              Панель управления
            </Link>
            <h1 className="text-xl font-bold">Управление мастерами</h1>
            <div className="w-32" />
          </div>
        </div>
      </header>

      <div className="container mx-auto px-4 py-8">
        <Card>
          <CardHeader>
            <CardTitle>Все мастера</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              {masters && masters.length > 0 ? (
                masters.map((master: any) => (
                  <div key={master.id} className="p-4 bg-white border rounded-lg">
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-4">
                        <div className="w-12 h-12 bg-rose-100 rounded-full flex items-center justify-center">
                          <User className="w-6 h-6 text-rose-600" />
                        </div>
                        <div>
                          <p className="font-semibold">{master.name}</p>
                          <p className="text-sm text-gray-600">{master.specialty}</p>
                          <p className="text-xs text-gray-500">Опыт: {master.experience_years} лет</p>
                        </div>
                      </div>
                      <div className="text-right">
                        <p className="text-sm font-medium">Рейтинг: {master.rating}</p>
                        <p className="text-xs text-gray-500">Отзывов: {master.total_reviews}</p>
                      </div>
                    </div>
                  </div>
                ))
              ) : (
                <p className="text-center text-gray-500 py-8">Мастера не найдены</p>
              )}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  )
}